import React, { useState, useEffect, useCallback } from 'react';
import { invoke } from '@forge/bridge';
import GanttChart from './components/GanttChart';
import ListView from './components/ListView';
import ViewSidebar from './components/ViewSidebar';
import EventModal from './components/EventModal';
import ConfigPanel from './components/ConfigPanel';
import IssuePreview from './components/IssuePreview';

const MONTH_NAMES = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December',
];
const ACTIVE_VIEW_KEY = 'team_gantt_active_view_id';

function getFieldValue(fields, key) {
  const v = fields?.[key];
  if (v == null) return null;
  if (typeof v === 'string') return v || null;
  if (typeof v === 'number') return String(v);
  if (Array.isArray(v)) {
    if (!v.length) return null;
    const f = v[0];
    return typeof f === 'string' ? f : (f?.displayName || f?.name || f?.value || null);
  }
  return v.displayName || v.name || v.value || v.key || null;
}

function extractGroupOptions(issues, fieldId) {
  const seen = new Set();
  for (const issue of issues) {
    const v = getFieldValue(issue.fields, fieldId);
    if (v) seen.add(v);
  }
  return Array.from(seen).sort();
}

export default function App() {
  const today = new Date();

  const [issues, setIssues]                     = useState([]);
  const [customEvents, setCustomEvents]           = useState([]);
  const [availableProjects, setAvailableProjects] = useState([]);
  const [availableFields, setAvailableFields]     = useState([]);
  const [loading, setLoading]                     = useState(true);
  const [error, setError]                         = useState(null);

  const [views, setViews]     = useState([]);
  const [folders, setFolders] = useState([]);
  const [activeViewId, setActiveViewId] = useState(
    () => localStorage.getItem(ACTIVE_VIEW_KEY) || 'default'
  );
  const [showSidebar, setShowSidebar] = useState(true);

  // Per-view config
  const [selectedProjects, setSelectedProjects] = useState([]);
  const [statusFilter, setStatusFilter]         = useState('active');
  const [jqlFilter, setJqlFilter]               = useState('');
  const [groupByField1, setGroupByField1]       = useState('labels');
  const [groupByField2, setGroupByField2]       = useState('assignee');
  const [startDateField, setStartDateField]     = useState('customfield_10015');
  const [endDateField, setEndDateField]         = useState('duedate');
  const [listFields, setListFields]             = useState(['summary','status','assignee','customfield_10015','duedate']);

  // Scroll navigation for timeline
  // scrollTarget.seq increments each time to force re-trigger even for same month
  const [scrollTarget, setScrollTarget] = useState(null);
  // Visible month label (reported back from GanttChart on scroll)
  const [visYear, setVisYear]   = useState(today.getFullYear());
  const [visMonth, setVisMonth] = useState(today.getMonth());

  const [showEventModal, setShowEventModal] = useState(false);
  const [editingEvent, setEditingEvent]     = useState(null);
  const [pendingCreate, setPendingCreate]   = useState(null);
  const [showConfig, setShowConfig]         = useState(false);
  const [previewIssue, setPreviewIssue]     = useState(null);

  // ── Load everything on mount ──────────────────────────────────────────────
  useEffect(() => {
    Promise.all([
      invoke('getViews'),
      invoke('getProjects'),
      invoke('getCustomEvents'),
      invoke('getFolders'),
      invoke('getFields'),
    ]).then(([viewsData, projectsData, eventsData, foldersData, fieldsData]) => {
      const loadedViews = viewsData || [];
      setViews(loadedViews);
      setFolders(foldersData || []);
      setAvailableFields(fieldsData || []);

      const projects = (projectsData.values || []).map(p => ({ key: p.key, name: p.name }));
      setAvailableProjects(projects);
      setCustomEvents(eventsData || []);

      const savedId = localStorage.getItem(ACTIVE_VIEW_KEY) || 'default';
      const active = loadedViews.find(v => v.id === savedId) || loadedViews[0];
      if (active) applyView(active);
    }).catch(() => {});
  }, []);

  function applyView(view) {
    setActiveViewId(view.id);
    setSelectedProjects(view.selectedProjects || []);
    setStatusFilter(view.statusFilter || 'active');
    setJqlFilter(view.jqlFilter || '');
    setGroupByField1(view.groupByField1 || 'labels');
    setGroupByField2(view.groupByField2 || 'assignee');
    setStartDateField(view.startDateField || 'customfield_10015');
    setEndDateField(view.endDateField || 'duedate');
    setListFields(view.listFields || ['summary','status','assignee','customfield_10015','duedate']);
  }

  // ── Fetch issues ──────────────────────────────────────────────────────────
  const fetchIssues = useCallback(async () => {
    const customJql = jqlFilter.trim();
    if (!customJql && selectedProjects.length === 0) {
      setIssues([]);
      setLoading(false);
      return;
    }
    setLoading(true);
    setError(null);

    try {
      let jql;
      if (customJql) {
        jql = customJql.includes('ORDER BY') ? customJql : `${customJql} ORDER BY assignee ASC`;
      } else {
        const projectClause = selectedProjects.join(', ');
        const statusClause = statusFilter === 'active' ? 'AND statusCategory != Done' : '';
        jql = [`project in (${projectClause})`, statusClause, 'ORDER BY assignee ASC']
          .filter(Boolean).join(' ');
      }

      const defaultFields = ['summary','assignee','status','priority','duedate','customfield_10015','labels','issuetype','project','resolution','reporter'];
      const extraFields = [groupByField1, groupByField2, startDateField, endDateField].filter(f =>
        f && !defaultFields.includes(f)
      );

      const allIssues = [];
      let nextPageToken = undefined;
      let pageCount = 0;

      while (pageCount < 10) {
        const result = await invoke('getIssues', { jql, nextPageToken, extraFields });
        allIssues.push(...(result.issues || []));
        if (result.isLast || !result.nextPageToken) break;
        nextPageToken = result.nextPageToken;
        pageCount++;
      }

      setIssues(allIssues);
    } catch (err) {
      setError(err.message || 'Failed to load issues');
    } finally {
      setLoading(false);
    }
  }, [selectedProjects, statusFilter, jqlFilter, groupByField1, groupByField2, startDateField, endDateField]);

  useEffect(() => {
    const customJql = jqlFilter.trim();
    if (selectedProjects.length > 0 || customJql) fetchIssues();
    else setLoading(false);
  }, [fetchIssues]);

  // ── View management ───────────────────────────────────────────────────────
  function switchView(viewId) {
    const view = views.find(v => v.id === viewId);
    if (!view) return;
    localStorage.setItem(ACTIVE_VIEW_KEY, viewId);
    applyView(view);
  }

  async function createView(name, folderId = null, viewType = 'timeline') {
    const newView = {
      name, selectedProjects, statusFilter, jqlFilter,
      groupByField1, groupByField2, startDateField, endDateField,
      listFields, viewType, folderId, isDefault: false,
    };
    const saved = await invoke('saveView', { view: newView });
    setViews(prev => [...prev, saved]);
    switchView(saved.id);
  }

  async function renameView(viewId, newName) {
    const view = views.find(v => v.id === viewId);
    if (!view) return;
    const updated = { ...view, name: newName };
    await invoke('saveView', { view: updated });
    setViews(prev => prev.map(v => v.id === viewId ? updated : v));
  }

  async function deleteView(viewId) {
    const result = await invoke('deleteView', { id: viewId });
    if (!result.success) return;
    const updated = views.filter(v => v.id !== viewId);
    setViews(updated);
    if (activeViewId === viewId && updated.length > 0) switchView(updated[0].id);
  }

  async function moveViewToFolder(viewId, folderId) {
    const view = views.find(v => v.id === viewId);
    if (!view) return;
    const updated = { ...view, folderId: folderId || null };
    await invoke('saveView', { view: updated });
    setViews(prev => prev.map(v => v.id === viewId ? updated : v));
  }

  async function saveCurrentView() {
    const view = views.find(v => v.id === activeViewId);
    if (!view) return;
    const updated = {
      ...view, selectedProjects, statusFilter, jqlFilter,
      groupByField1, groupByField2, startDateField, endDateField, listFields,
    };
    await invoke('saveView', { view: updated });
    setViews(prev => prev.map(v => v.id === activeViewId ? updated : v));
    setShowConfig(false);
  }

  // ── Folder management ─────────────────────────────────────────────────────
  async function createFolder(name) {
    const saved = await invoke('saveFolder', { folder: { name } });
    setFolders(prev => [...prev, saved]);
    return saved;
  }

  async function renameFolder(folderId, newName) {
    const folder = folders.find(f => f.id === folderId);
    if (!folder) return;
    const updated = { ...folder, name: newName };
    await invoke('saveFolder', { folder: updated });
    setFolders(prev => prev.map(f => f.id === folderId ? updated : f));
  }

  async function deleteFolder(folderId) {
    await invoke('deleteFolder', { id: folderId });
    setFolders(prev => prev.filter(f => f.id !== folderId));
    setViews(prev => prev.map(v => v.folderId === folderId ? { ...v, folderId: null } : v));
  }

  // ── Custom event CRUD ─────────────────────────────────────────────────────
  function openCreateEvent() {
    setPendingCreate(null);
    setEditingEvent(null);
    setShowEventModal(true);
  }

  function openEditEvent(event) {
    setPendingCreate(null);
    setEditingEvent(event);
    setShowEventModal(true);
  }

  function handleCreateEvent({ startDate, endDate, g1, g2 }) {
    setEditingEvent(null);
    setPendingCreate({ startDate, endDate, group1Value: g1, group2Value: g2 });
    setShowEventModal(true);
  }

  function closeEventModal() {
    setShowEventModal(false);
    setEditingEvent(null);
    setPendingCreate(null);
  }

  async function saveEvent(eventData) {
    const activeView = views.find(v => v.id === activeViewId);
    const folderId = activeView?.folderId ?? null;
    const withFolder = { ...eventData, folderId };
    const saved = await invoke('saveCustomEvent', { event: withFolder });
    setCustomEvents(prev => eventData.id
      ? prev.map(e => e.id === eventData.id ? saved : e)
      : [...prev, saved]
    );
    closeEventModal();
  }

  async function deleteEvent(id) {
    await invoke('deleteCustomEvent', { id });
    setCustomEvents(prev => prev.filter(e => e.id !== id));
  }

  async function updateEventDates(event, newStartDate, newEndDate) {
    const updated = { ...event, startDate: newStartDate, endDate: newEndDate };
    // Optimistic update immediately — packing re-evaluates right away
    setCustomEvents(prev => prev.map(e => e.id === event.id ? updated : e));
    const saved = await invoke('saveCustomEvent', { event: updated });
    setCustomEvents(prev => prev.map(e => e.id === event.id ? saved : e));
  }

  async function updateIssueDates(key, newStartDate, newEndDate) {
    // Optimistic update immediately — packing re-evaluates right away
    setIssues(prev => prev.map(iss => {
      if (iss.key !== key) return iss;
      return {
        ...iss,
        fields: {
          ...iss.fields,
          [startDateField || 'customfield_10015']: newStartDate,
          [endDateField   || 'duedate']:            newEndDate,
        },
      };
    }));
    await invoke('updateIssueDates', { key, startDate: newStartDate, dueDate: newEndDate });
  }

  // ── Timeline navigation ───────────────────────────────────────────────────
  function navigateTo(year, month) {
    setVisYear(year);
    setVisMonth(month);
    setScrollTarget({ year, month, seq: Date.now() });
  }

  function navigateMonth(delta) {
    const d = new Date(visYear, visMonth + delta, 1);
    navigateTo(d.getFullYear(), d.getMonth());
  }

  function jumpToToday() {
    navigateTo(today.getFullYear(), today.getMonth());
  }

  // ── Derived state ─────────────────────────────────────────────────────────
  const activeView = views.find(v => v.id === activeViewId);
  const viewType   = activeView?.viewType || 'timeline';

  const visibleCustomEvents = customEvents.filter(e =>
    (e.folderId ?? null) === (activeView?.folderId ?? null)
  );

  const fieldLabel = (id) => availableFields.find(f => f.id === id)?.name || id;
  const groupByField1Label = fieldLabel(groupByField1);
  const groupByField2Label = fieldLabel(groupByField2);

  const groupOptions1 = extractGroupOptions(issues, groupByField1);
  const groupOptions2 = extractGroupOptions(issues, groupByField2);

  const monthLabel = `${MONTH_NAMES[visMonth]} ${visYear}`;

  return (
    <div style={styles.root}>
      {/* ── Toolbar ── */}
      <div style={styles.toolbar}>
        <button style={styles.sidebarToggle} onClick={() => setShowSidebar(v => !v)} title="Toggle sidebar">☰</button>
        <span style={styles.appTitle}>🗓 Team Gantt</span>
        {activeView && (
          <span style={styles.viewName}>
            {activeView.viewType === 'list' ? '≡ ' : '▤ '}{activeView.name}
          </span>
        )}

        {viewType === 'timeline' && (
          <div style={styles.navGroup}>
            <button style={styles.navBtn} onClick={() => navigateMonth(-1)}>‹</button>
            <span style={styles.monthLabel}>{monthLabel}</span>
            <button style={styles.navBtn} onClick={() => navigateMonth(1)}>›</button>
            <button style={styles.todayBtn} onClick={jumpToToday}>Today</button>
          </div>
        )}

        <div style={styles.toolbarRight}>
          {viewType === 'timeline' && (
            <button style={styles.addEventBtn} onClick={openCreateEvent}>+ Add Event</button>
          )}
          <button style={styles.configBtn} onClick={() => setShowConfig(v => !v)} title="Configure view">⚙ Configure</button>
          <button style={styles.refreshBtn} onClick={fetchIssues} title="Refresh">↺</button>
        </div>
      </div>

      {/* ── Layout ── */}
      <div style={styles.layout}>
        {showSidebar && (
          <ViewSidebar
            views={views}
            folders={folders}
            activeViewId={activeViewId}
            onSwitch={switchView}
            onCreate={createView}
            onRename={renameView}
            onDelete={deleteView}
            onMoveToFolder={moveViewToFolder}
            onCreateFolder={createFolder}
            onRenameFolder={renameFolder}
            onDeleteFolder={deleteFolder}
          />
        )}

        <div style={styles.content}>
          {error && (
            <div style={styles.errorBanner}>
              ⚠️ {error}
              <button style={styles.retryBtn} onClick={fetchIssues}>Retry</button>
            </div>
          )}
          {loading ? (
            <div style={styles.loadingWrap}>
              <div style={styles.spinner} />
              <p style={styles.loadingText}>Loading issues…</p>
            </div>
          ) : viewType === 'list' ? (
            <ListView
              issues={issues}
              customEvents={visibleCustomEvents}
              listFields={listFields}
              availableFields={availableFields}
              startDateField={startDateField}
              endDateField={endDateField}
              groupByField1={groupByField1}
              groupByField2={groupByField2}
              groupByField1Label={groupByField1Label}
              groupByField2Label={groupByField2Label}
              groupOptions1={groupOptions1}
              groupOptions2={groupOptions2}
              onEditEvent={openEditEvent}
              onPreviewIssue={setPreviewIssue}
              onAddEvent={openCreateEvent}
              onSaveEvent={saveEvent}
            />
          ) : (
            <GanttChart
              issues={issues}
              customEvents={visibleCustomEvents}
              today={today}
              groupByField1={groupByField1}
              groupByField2={groupByField2}
              groupByField1Label={groupByField1Label}
              groupByField2Label={groupByField2Label}
              startDateField={startDateField}
              endDateField={endDateField}
              scrollToTarget={scrollTarget}
              onVisibleMonthChange={(y, m) => { setVisYear(y); setVisMonth(m); }}
              onEditEvent={openEditEvent}
              onDeleteEvent={deleteEvent}
              onUpdateEvent={updateEventDates}
              onUpdateIssue={updateIssueDates}
              onCreateEvent={handleCreateEvent}
              onPreviewIssue={setPreviewIssue}
            />
          )}
        </div>

        {showConfig && (
          <ConfigPanel
            availableProjects={availableProjects}
            availableFields={availableFields}
            selectedProjects={selectedProjects}
            statusFilter={statusFilter}
            jqlFilter={jqlFilter}
            groupByField1={groupByField1}
            groupByField2={groupByField2}
            startDateField={startDateField}
            endDateField={endDateField}
            viewType={viewType}
            listFields={listFields}
            onProjectsChange={setSelectedProjects}
            onStatusFilterChange={setStatusFilter}
            onJqlFilterChange={setJqlFilter}
            onGroupByField1Change={setGroupByField1}
            onGroupByField2Change={setGroupByField2}
            onStartDateFieldChange={setStartDateField}
            onEndDateFieldChange={setEndDateField}
            onListFieldsChange={setListFields}
            onSave={saveCurrentView}
            onClose={() => setShowConfig(false)}
          />
        )}
      </div>

      {previewIssue && (
        <IssuePreview
          issue={previewIssue}
          startDateField={startDateField}
          endDateField={endDateField}
          onClose={() => setPreviewIssue(null)}
        />
      )}

      {showEventModal && (
        <EventModal
          event={editingEvent}
          groupByField1={groupByField1}
          groupByField2={groupByField2}
          groupByField1Label={groupByField1Label}
          groupByField2Label={groupByField2Label}
          groupOptions1={groupOptions1}
          groupOptions2={groupOptions2}
          initialStartDate={pendingCreate?.startDate}
          initialEndDate={pendingCreate?.endDate}
          initialGroup1Value={pendingCreate?.group1Value}
          initialGroup2Value={pendingCreate?.group2Value}
          onSave={saveEvent}
          onClose={closeEventModal}
        />
      )}
    </div>
  );
}

const styles = {
  root: { display: 'flex', flexDirection: 'column', height: '100vh', fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif", fontSize: '13px', color: '#172B4D', background: '#F4F5F7' },
  toolbar: { display: 'flex', alignItems: 'center', gap: '10px', padding: '8px 16px', background: '#fff', borderBottom: '1px solid #DFE1E6', flexShrink: 0, flexWrap: 'wrap' },
  sidebarToggle: { background: 'none', border: '1px solid #DFE1E6', borderRadius: '4px', width: '30px', height: '30px', cursor: 'pointer', fontSize: '14px', color: '#6B778C', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  appTitle: { fontWeight: 700, fontSize: '15px', color: '#0052CC' },
  viewName: { fontSize: '13px', color: '#6B778C', fontWeight: 500, borderLeft: '1px solid #DFE1E6', paddingLeft: '10px' },
  navGroup: { display: 'flex', alignItems: 'center', gap: '6px', marginLeft: '8px' },
  navBtn: { background: 'none', border: '1px solid #DFE1E6', borderRadius: '4px', width: '28px', height: '28px', cursor: 'pointer', fontSize: '16px', color: '#172B4D', display: 'flex', alignItems: 'center', justifyContent: 'center' },
  monthLabel: { fontWeight: 600, fontSize: '14px', minWidth: '160px', textAlign: 'center' },
  todayBtn: { background: '#0052CC', color: '#fff', border: 'none', borderRadius: '4px', padding: '4px 10px', cursor: 'pointer', fontSize: '12px', fontWeight: 600 },
  toolbarRight: { display: 'flex', alignItems: 'center', gap: '8px', marginLeft: 'auto' },
  addEventBtn: { background: '#0052CC', color: '#fff', border: 'none', borderRadius: '4px', padding: '5px 12px', cursor: 'pointer', fontSize: '12px', fontWeight: 600 },
  configBtn: { border: '1px solid #DFE1E6', borderRadius: '4px', padding: '4px 10px', cursor: 'pointer', fontSize: '12px', background: '#fff', color: '#172B4D' },
  refreshBtn: { background: 'none', border: '1px solid #DFE1E6', borderRadius: '4px', width: '28px', height: '28px', cursor: 'pointer', fontSize: '16px', color: '#172B4D' },
  layout: { flex: 1, display: 'flex', overflow: 'hidden', position: 'relative' },
  content: { flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column' },
  errorBanner: { background: '#FFEBE6', color: '#DE350B', padding: '8px 16px', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '13px', flexShrink: 0 },
  retryBtn: { background: '#DE350B', color: '#fff', border: 'none', borderRadius: '4px', padding: '3px 8px', cursor: 'pointer', fontSize: '11px' },
  loadingWrap: { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '12px' },
  spinner: { width: '32px', height: '32px', borderRadius: '50%', border: '3px solid #DFE1E6', borderTopColor: '#0052CC', animation: 'spin 0.8s linear infinite' },
  loadingText: { color: '#6B778C', margin: 0 },
};
